        import javax.faces.context.FacesContext;
        import javax.servlet.http.HttpSession;
        import sailpoint.object.CustomGlobal;

        HttpSession session;
        FacesContext fc= FacesContext.getCurrentInstance();
        if(fc!=null){
            session = (HttpSession) fc.getExternalContext().getSession(true);
        }
        CustomGlobal.put("httpSession",session);


  import sailpoint.object.Identity;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
 
  Identity identity=context.getObjectByName(Identity.class,launcher);
  if(identity.getManagerStatus()){
      return "true";
  }
  List workGroups=null;
  QueryOptions qo=new QueryOptions();
  Filter filter=Filter.ignoreCase(Filter.and(Filter.eq("workgroup",true),Filter.like("name","Trusted Requesters", Filter.MatchMode.START)));
  qo.add(filter);
  workGroups= context.getObjects(Identity.class,qo);
  if(workGroups.size()>0){
      for(Identity wrkGrpObj:workGroups){
          if(identity.isInWorkGroup(wrkGrpObj)){
              return "true";
          }
      }
  }
  return "false";


  if(wfcase.hasErrors()){
    workflow.put("stepName" , wfcontext.getStep().getName());
    return true;
  } else{
    return false;
  }


