    return true;
  } else{
    return false;
  }

      
        import javax.faces.application.FacesMessage;
        import sailpoint.tools.Util;
        import sailpoint.object.CustomGlobal;
        
        addMessage(wfcontext, "Entering Step: "+wfcontext.getStep().getName());
        try{
            httpSession = CustomGlobal.get("httpSession");
            
            if (httpSession != null) {
                List currentMessages = httpSession.getAttribute("sailpoint.web.PageCodeBase.sessionMessages");  
                FacesMessage myMessage = null;

                String message = "Request has been submitted successfully.";
                myMessage = new FacesMessage(FacesMessage.SEVERITY_INFO,message+".","Success");  

                List myMessages = new ArrayList();  
                myMessages.add(myMessage);  
                httpSession.setAttribute("sailpoint.web.PageCodeBase.sessionMessages", myMessages);
            }
            CustomGlobal.remove("httpSession");
        } catch(Exception e) {
            error(logName, "Exception encountered in: "+wfcontext.getStep().getName(),e);
            handleWorkFlowException(wfcontext, e);
        }
        addMessage(wfcontext, "Exiting Step: "+wfcontext.getStep().getName());


  if(wfcase.hasErrors()){
    workflow.put("stepName" , wfcontext.getStep().getName());
    return true;
  } else{
    return false;
  }

      
        import java.util.List;
        import java.util.ArrayList;
        import java.util.Arrays;
        import sailpoint.object.Identity;
        import sailpoint.object.WorkItem;
        import sailpoint.object.WorkItem.OwnerHistory;
        import sailpoint.server.Auditor;
        import sailpoint.object.AuditEvent;
        import sailpoint.object.Certification;
        
        trace(logName,"Entering Step: "+wfcontext.getStep().getName());
        addMessage(wfcontext, "Entering Step: "+wfcontext.getStep().getName());
        try {
            Identity launcherIdentity=context.getObjectByName(Identity.class,launcher);
            List workItemsList = formModel.get("workitem");
            WorkItem  wi = null;
            Identity oldOwner = null;
            OwnerHistory oh = null;
            List ohList = null;
            String action = "Comment";
            String certId = null;
            Certification certObj = null;  
            
            for(String workitem: workItemsList){
                String wiId = workitem.split("###")[1];
                wi = context.getObjectById(WorkItem.class,wiId);
                certId = wi.getCertification();
                oldOwner = wi.getOwner();
                oh = new OwnerHistory( oldOwner,  launcherIdentity, "Owner Changed");
                ohList = new ArrayList();
                ohList.add(oh);
                wi.setOwnerHistory(ohList);
                wi.setOwner(launcherIdentity);
                certObj = context.getObjectById(Certification.class,certId);
                certObj.setCertifierIdentities(Arrays.asList(launcherIdentity));
                context.saveObject(wi); 
                context.saveObject(certObj);
                context.commitTransaction();

                if (Auditor.isEnabled(action)){
                    String auditString1 = "Certification workitem that is Reassigned: "+workitem.split("###")[0];
                    String oldOw =  oldOwner != null ? oldOwner.getName(): "OldOwner not found";
                    String auditString2 = "Old Owner : "+ oldOw;
                    String auditString3 = "New Owner : "+launcherIdentity.getName();
                    AuditEvent event = new AuditEvent();
                    event.setAction(action);
                    event.setSource("Reassign Certification Workitems");
                    event.setTarget(oldOwner.getName());
                    event.setString1(auditString1);
                    event.setString2(auditString2);
                    event.setString3(auditString3);
                    Auditor.log(event);
                    context.commitTransaction();
                }
            }       
        } catch(Exception e) {
            error(logName, "Exception encountered in: "+wfcontext.getStep().getName(),e);
            handleWorkFlowException(wfcontext, e);
        }
       addMessage(wfcontext, "Exiting Step: "+wfcontext.getStep().getName());
       trace(logName,"Exiting Step: "+wfcontext.getStep().getName());


  if(wfcase.hasErrors()){
    workflow.put("stepName" , wfcontext.getStep().getName());
    return true;
  } else{
    return false;
  }


  if(wfcase.hasErrors()){
      throw new RuntimeException("ERROR: in step - " + workflow.get("stepName") + " : " + wfcase.getErrors());
  }
